"use client";

import { useEffect, useRef, useState } from "react";
import { useScroll, useTransform, motion, MotionValue } from "framer-motion";
import { productData } from "@/data/product";

export default function HeroCanvas() {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });
  
  const [images, setImages] = useState<HTMLImageElement[]>([]);
  
  // Pre-load images to prevent flickering
  useEffect(() => {
    const loadedImages: HTMLImageElement[] = [];
    let loadedCount = 0;
    
    for (let i = 1; i <= 240; i++) {
      const img = new Image();
      const frameNumber = i.toString().padStart(3, '0');
      img.src = `/images/sequence/frame-${frameNumber}.jpg`;
      img.onload = () => {
        loadedCount++;
        if (loadedCount === 240) {
          setImages(loadedImages);
        }
      };
      loadedImages.push(img);
    }
  }, []);

  // Map scroll progress to the 240 frames
  const frameIndex = useTransform(scrollYProgress, [0, 1], [0, 239]);

  // Main canvas drawing logic
  useEffect(() => {
    if (images.length === 0) return;
    
    // Draw first frame immediately
    drawFrame(0);

    const unsubscribe = frameIndex.on("change", (latest) => {
      drawFrame(Math.round(latest));
    });

    return () => unsubscribe();
  }, [images, frameIndex]);

  const drawFrame = (idx: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    
    const img = images[idx];
    if (img) {
      // Background cover logic for canvas
      const hRatio = canvas.width / img.width;
      const vRatio = canvas.height / img.height;
      const ratio  = Math.max(hRatio, vRatio);
      const centerShift_x = (canvas.width - img.width * ratio) / 2;
      const centerShift_y = (canvas.height - img.height * ratio) / 2;  
      
      ctx.clearRect(0,0,canvas.width, canvas.height);
      ctx.drawImage(img, 0,0, img.width, img.height,
                          centerShift_x,centerShift_y,img.width*ratio, img.height*ratio);
    }
  };

  // Resize canvas according to window size
  useEffect(() => {
    const handleResize = () => {
      if (canvasRef.current) {
        canvasRef.current.width = window.innerWidth;
        canvasRef.current.height = window.innerHeight;
        // Redraw current frame
        drawFrame(Math.round(frameIndex.get()));
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, [images, frameIndex]);

  // Fade out the entire hero container at the very end to hand off to static bottle
  const globalOpacity = useTransform(scrollYProgress, [0.95, 1], [1, 0]);

  return (
    <div ref={containerRef} className="relative h-[500vh] bg-clean-black">
      <motion.div style={{ opacity: globalOpacity }} className="sticky top-0 h-screen w-full overflow-hidden">
        <canvas ref={canvasRef} className="w-full h-full object-cover" />
        
        {/* Animated Overlays */}
        {productData.sections.map((section) => (
          <OverlayCard key={section.id} section={section} scrollYProgress={scrollYProgress} />
        ))}
      </motion.div>
    </div>
  );
}

function OverlayCard({ section, scrollYProgress }: { section: typeof productData.sections[0], scrollYProgress: MotionValue<number> }) {
  // Translate frames to 0-1 percentage of the 500vh scroll
  const TOTAL_FRAMES = 240;
  const startP = section.startFrame / TOTAL_FRAMES;
  const endP = section.endFrame / TOTAL_FRAMES;
  const midP = startP + (endP - startP) / 2;
  
  const opacity = useTransform(scrollYProgress, 
    [startP, startP + 0.05, endP - 0.05, endP], 
    [0, 1, 1, 0]
  );
  
  const y = useTransform(scrollYProgress, 
    [startP, startP + 0.05], 
    [30, 0]
  );

  return (
    <motion.div 
      style={{ opacity, y }}
      className="absolute inset-0 flex flex-col items-center justify-center text-center pointer-events-none p-6"
    >
      <h2 className="text-4xl md:text-6xl lg:text-7xl font-extrabold tracking-tighter text-white mb-6 uppercase">
        {section.title}
      </h2>
      <p className="text-lg md:text-2xl text-white/60 max-w-lg font-medium tracking-wide">
        {section.subtitle}
      </p>
    </motion.div>
  );
}
